#include <iostream>
#include <vector>
#include <sstream>
using namespace std;

int main() {
    string input;
    cout << "Enter a line of integers separated by spaces: ";
    getline(cin, input);

    istringstream iss(input);
    vector<int> nums;
    int num;

    while (iss >> num) {
        nums.push_back(num);
    }

    int sum = 0;
    for (int n : nums) {
        sum += n;
    }

    cout << "Sum of all elements: " << sum << endl;
    return 0;
}
```

